import modal
from fastapi import FastAPI
from pydantic import BaseModel
import requests

app = modal.App("fastapi-json-transform")

image = modal.Image.debian_slim().pip_install("fastapi", "requests")

web_app = FastAPI()

class TransformRequest(BaseModel):
    data: list
    operation: str

@web_app.get("/")
def read_root():
    return {"status": "ok", "service": "json-transform"}

@web_app.post("/transform")
def transform(req: TransformRequest):
    if req.operation == "reverse":
        res = list(reversed(req.data))
    elif req.operation == "sort":
        res = sorted(req.data)
    else:
        res = req.data
    return {"result": res}

@app.function(image=image)
@modal.asgi_app()
def fastapi_app():
    return web_app

@app.local_entrypoint()
def main():
    url = fastapi_app.web_url
    print(f"Endpoint URL: {url}")

    response = requests.get(url)
    health_check = "ok" if response.status_code == 200 else "error"

    d = modal.Dict.from_name("fastapi-json-transform-output", create_if_missing=True)
    d["health_check"] = health_check
    d["endpoint_deployed"] = True

